/* Demonstration of use-after-free prevention */
void demonstrate_uaf_prevention(void) {
    printf("\n--- Demonstrating Use-After-Free Prevention ---\n\n");

    /* Create a session */
    const char *sid = session_create();
    if (sid == NULL) {
        fprintf(stderr, "Failed to create session\n");
        return;
    }

    /* Copy session ID since we need it after invalidation */
    char session_id[SESSION_ID_LEN];
    strncpy(session_id, sid, SESSION_ID_LEN - 1);
    session_id[SESSION_ID_LEN - 1] = '\0';

    /* Set some data */
    session_set_attribute(session_id, "username", "alice");
    session_set_attribute(session_id, "role", "admin");

    /* Read data back */
    const char *username = session_get_attribute(session_id, "username");
    if (username) {
        printf("Before invalidation - username: %s\n", username);
    }

    /* Invalidate the session (this frees data and NULLs the pointer) */
    session_invalidate(session_id);

    /*
     * Attempt to access the invalidated session.
     * Without UAF prevention, this would access freed memory.
     * With our protection, session_access detects the expired state
     * and re-initializes with fresh data.
     */
    printf("\nAccessing after invalidation (safe re-initialization):\n");
    Session *session = session_access(session_id);
    if (session != NULL) {
        printf("Session re-initialized successfully. Data pointer: %p\n", (void *)session->data);
        /* The old data is gone - this is safe, fresh memory */
        const char *old_username = session_get_attribute(session_id, "username");
        if (old_username == NULL) {
            printf("Old 'username' attribute correctly not found (fresh session)\n");
        }
    }

    /* Set new data on re-initialized session */
    session_set_attribute(session_id, "username", "bob");
    username = session_get_attribute(session_id, "username");
    if (username) {
        printf("After re-init - username: %s\n", username);
    }

    printf("\n--- UAF Prevention Demo Complete ---\n");
}

